import{_ as a,o as t,c as r,ai as o}from"./chunks/framework.CaiDwmc7.js";const f=JSON.parse('{"title":"Bifröst Privacy Policy","description":"","frontmatter":{},"headers":[],"relativePath":"legal/privacy.md","filePath":"legal/privacy.md"}'),i={name:"legal/privacy.md"};function s(n,e,l,c,d,h){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="bifrost-privacy-policy" tabindex="-1">Bifröst Privacy Policy <a class="header-anchor" href="#bifrost-privacy-policy" aria-label="Permalink to “Bifröst Privacy Policy”">​</a></h1><p><strong>Last Updated:</strong> March 7, 2026</p><h2 id="_1-overview" tabindex="-1">1. Overview <a class="header-anchor" href="#_1-overview" aria-label="Permalink to “1. Overview”">​</a></h2><p>Bifröst is designed with minimal data collection. The bot only stores the information necessary to operate its server and channel bridging functionality.</p><h2 id="_2-data-collected" tabindex="-1">2. Data Collected <a class="header-anchor" href="#_2-data-collected" aria-label="Permalink to “2. Data Collected”">​</a></h2><p>Bifröst may store the following Discord identifiers:</p><ul><li><strong>Server IDs</strong> — when servers are linked</li><li><strong>Channel IDs</strong> — when channels are linked between servers</li><li><strong>Message IDs</strong> — used for message deletion propagation across bridged channels</li></ul><h2 id="_3-data-not-collected" tabindex="-1">3. Data Not Collected <a class="header-anchor" href="#_3-data-not-collected" aria-label="Permalink to “3. Data Not Collected”">​</a></h2><p>Bifröst does <strong>not</strong> store:</p><ul><li>Message content</li><li>Usernames</li><li>User IDs</li><li>Attachments</li><li>Any personal information</li></ul><h2 id="_4-purpose-of-data-storage" tabindex="-1">4. Purpose of Data Storage <a class="header-anchor" href="#_4-purpose-of-data-storage" aria-label="Permalink to “4. Purpose of Data Storage”">​</a></h2><p>Stored data is used solely for the following purposes:</p><ul><li>Maintaining links between servers</li><li>Maintaining links between channels</li><li>Synchronizing message deletions across bridged channels</li></ul><h2 id="_5-data-retention" tabindex="-1">5. Data Retention <a class="header-anchor" href="#_5-data-retention" aria-label="Permalink to “5. Data Retention”">​</a></h2><p>Data is retained only for as long as necessary for the bot to function.<br> If a bridge is removed or the bot is removed from a server, associated data may be deleted.</p><h2 id="_6-data-sharing" tabindex="-1">6. Data Sharing <a class="header-anchor" href="#_6-data-sharing" aria-label="Permalink to “6. Data Sharing”">​</a></h2><p>Bifröst does <strong>not sell, share, or distribute</strong> stored data to third parties.</p><h2 id="_7-security" tabindex="-1">7. Security <a class="header-anchor" href="#_7-security" aria-label="Permalink to “7. Security”">​</a></h2><p>Reasonable measures are taken to protect stored data. However, no method of electronic storage or transmission over the internet is completely secure.</p><h2 id="_8-changes-to-this-policy" tabindex="-1">8. Changes to This Policy <a class="header-anchor" href="#_8-changes-to-this-policy" aria-label="Permalink to “8. Changes to This Policy”">​</a></h2><p>This Privacy Policy may be updated from time to time. Continued use of the bot constitutes acceptance of any updates.</p><h2 id="_9-self-hosted-instances" tabindex="-1">9. Self-Hosted Instances <a class="header-anchor" href="#_9-self-hosted-instances" aria-label="Permalink to “9. Self-Hosted Instances”">​</a></h2><p>Bifröst is open-source software and may be self-hosted by third parties.</p><p>This Privacy Policy applies only to the <strong>official instance of Bifröst operated by the developer</strong>.</p><p>If you interact with a self-hosted instance, the operator of that instance is responsible for any data storage or processing performed by their deployment.</p><h2 id="_10-contact" tabindex="-1">10. Contact <a class="header-anchor" href="#_10-contact" aria-label="Permalink to “10. Contact”">​</a></h2><p>If you have questions about this Privacy Policy, contact:</p><p><strong>Email:</strong> <a href="mailto:contact@bifrost-bot.com" target="_blank" rel="noreferrer">contact@bifrost-bot.com</a></p>',28)])])}const g=a(i,[["render",s]]);export{f as __pageData,g as default};
